    @WebMethod(operationName = "processPayment")
    public PaymentResponse processPayment(
            @WebParam(name = "paymentRequest") PaymentRequest request) {

        PaymentResponse response = new PaymentResponse();

        try {
            // Validate request
            if (request == null) {
                response.setStatus("FAILED");
                response.setMessage("Payment request is null");
                response.setTransactionId(null);
                return response;
            }

            if (request.getAmount() <= 0) {
                response.setStatus("FAILED");
                response.setMessage("Invalid payment amount: must be greater than zero");
                response.setTransactionId(null);
                return response;
            }

            if (request.getCardNumber() == null || request.getCardNumber().isEmpty()) {
                response.setStatus("FAILED");
                response.setMessage("Card number is required");
                response.setTransactionId(null);
                return response;
            }

            if (request.getMerchantId() == null || request.getMerchantId().isEmpty()) {
                response.setStatus("FAILED");
                response.setMessage("Merchant ID is required");
                response.setTransactionId(null);
                return response;
            }

            // Generate transaction ID
            String transactionId = "TXN-" + UUID.randomUUID().toString().substring(0, 12).toUpperCase();

            // Process payment based on message content
            String paymentType = request.getPaymentType();
            double amount = request.getAmount();
            String currency = request.getCurrency() != null ? request.getCurrency() : "USD";

            boolean paymentSuccess = processPaymentTransaction(request);

            if (paymentSuccess) {
                PaymentRecord record = new PaymentRecord();
                record.setTransactionId(transactionId);
                record.setAmount(amount);
                record.setCurrency(currency);
                record.setMerchantId(request.getMerchantId());
                record.setMaskedCardNumber(maskCardNumber(request.getCardNumber()));
                record.setPaymentType(paymentType);
                record.setTimestamp(new Date());
                record.setStatus("APPROVED");

                paymentStore.put(transactionId, record);

                response.setStatus("APPROVED");
                response.setTransactionId(transactionId);
                response.setMessage("Payment processed successfully. Amount: " + amount + " " + currency);
                response.setAuthorizationCode("AUTH-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase());
            } else {
                response.setStatus("DECLINED");
                response.setTransactionId(transactionId);
                response.setMessage("Payment declined by issuer");
                response.setAuthorizationCode(null);
            }

        } catch (Exception e) {
            response.setStatus("ERROR");
            response.setMessage("Payment processing error: " + e.getMessage());
            response.setTransactionId(null);
        }

        return response;
    }

    @WebMethod(operationName = "refundPayment")
    public PaymentResponse refundPayment(
            @WebParam(name = "transactionId") String transactionId,
            @WebParam(name = "amount") double amount) {

        PaymentResponse response = new PaymentResponse();

        PaymentRecord originalRecord = paymentStore.get(transactionId);
        if (originalRecord == null) {
            response.setStatus("FAILED");
            response.setMessage("Original transaction not found: " + transactionId);
            return response;
        }

        if (amount > originalRecord.getAmount()) {
            response.setStatus("FAILED");
            response.setMessage("Refund amount exceeds original transaction amount");
            return response;
        }

        String refundTxnId = "RFD-" + UUID.randomUUID().toString().substring(0, 12).toUpperCase();
        response.setStatus("REFUNDED");
        response.setTransactionId(refundTxnId);
        response.setMessage("Refund of " + amount + " " + originalRecord.getCurrency() + " processed for original transaction " + transactionId);
        response.setAuthorizationCode("RAUTH-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase());

        return response;
    }

    @WebMethod(operationName = "getTransactionStatus")
    public PaymentResponse getTransactionStatus(
            @WebParam(name = "transactionId") String transactionId) {

        PaymentResponse response = new PaymentResponse();
        PaymentRecord record = paymentStore.get(transactionId);

        if (record != null) {
            response.setStatus(record.getStatus());
            response.setTransactionId(record.getTransactionId());
            response.setMessage("Transaction found. Amount: " + record.getAmount() + " " + record.getCurrency() +
                    ", Card: " + record.getMaskedCardNumber() + ", Type: " + record.getPaymentType());
        } else {
            response.setStatus("NOT_FOUND");
            response.setMessage("Transaction not found: " + transactionId);
        }

        return response;
    }

    private boolean processPaymentTransaction(PaymentRequest request) {
        // Simulate payment processing logic based on content
        String cardNumber = request.getCardNumber();
        if (cardNumber != null && cardNumber.endsWith("0000")) {
            return false; // Simulate decline for test cards ending in 0000
        }

        double amount = request.getAmount();
        if (amount > 10000.00) {
            return false; // Decline high-value transactions for demo
        }

        String paymentType = request.getPaymentType();
        if ("CREDIT".equalsIgnoreCase(paymentType) || "DEBIT".equalsIgnoreCase(paymentType)
                || "PREPAID".equalsIgnoreCase(paymentType) || paymentType == null) {
            return true;
        }

        return true;
    }

    private String maskCardNumber(String cardNumber) {
        if (cardNumber == null || cardNumber.length() < 4) {
            return "****";
        }
        return "****-****-****-" + cardNumber.substring(cardNumber.length() - 4);
    }

