    // --- WS-Security Timestamp Handler ---

    public static class WsSecurityTimestampHandler implements SOAPHandler<SOAPMessageContext> {

        private static final String WSS_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
        private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
        private static final long TIMESTAMP_FRESHNESS_MS = 5 * 60 * 1000; // 5 minutes
        private static final int MAX_NONCE_CACHE_SIZE = 10000;

        // Cache for replay protection: stores message IDs/timestamps already seen
        private static final Set<String> processedMessageIds = Collections.newSetFromMap(new ConcurrentHashMap<>());
        private static final Deque<String> messageIdOrder = new ConcurrentLinkedDeque<>();

        private static final SimpleDateFormat ISO_FORMAT = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
        private static final SimpleDateFormat ISO_FORMAT_NO_MILLIS = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss'Z'");

        static {
            ISO_FORMAT.setTimeZone(TimeZone.getTimeZone("UTC"));
            ISO_FORMAT_NO_MILLIS.setTimeZone(TimeZone.getTimeZone("UTC"));
        }

        @Override
        public Set<QName> getHeaders() {
            Set<QName> headers = new HashSet<>();
            headers.add(new QName(WSS_NS, "Security"));
            return headers;
        }

        @Override
        public boolean handleMessage(SOAPMessageContext context) {
            Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

            if (outbound != null && outbound) {
                return handleOutboundMessage(context);
            } else {
                return handleInboundMessage(context);
            }
        }

        private boolean handleOutboundMessage(SOAPMessageContext context) {
            try {
                SOAPMessage message = context.getMessage();
                SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
                SOAPHeader header = envelope.getHeader();

                if (header == null) {
                    header = envelope.addHeader();
                }

                // Add WS-Security header with timestamp
                SOAPElement securityElement = header.addChildElement("Security", "wsse", WSS_NS);
                securityElement.addNamespaceDeclaration("wsu", WSU_NS);
                securityElement.addAttribute(
                        envelope.createName("mustUnderstand", "soap",
                                "http://schemas.xmlsoap.org/soap/envelope/"), "1");

                SOAPElement timestampElement = securityElement.addChildElement("Timestamp", "wsu", WSU_NS);

                String timestampId = "TS-" + UUID.randomUUID().toString();
                timestampElement.addAttribute(
                        envelope.createName("Id", "wsu", WSU_NS), timestampId);

                Date now = new Date();
                Date expires = new Date(now.getTime() + TIMESTAMP_FRESHNESS_MS);

                SOAPElement createdElement = timestampElement.addChildElement("Created", "wsu", WSU_NS);
                createdElement.addTextNode(formatTimestamp(now));

                SOAPElement expiresElement = timestampElement.addChildElement("Expires", "wsu", WSU_NS);
                expiresElement.addTextNode(formatTimestamp(expires));

                message.saveChanges();

                System.out.println("[WS-Security] Outbound timestamp added - Created: " + formatTimestamp(now) + ", Expires: " + formatTimestamp(expires));

                return true;
            } catch (SOAPException e) {
                System.err.println("[WS-Security] Error adding security header: " + e.getMessage());
                throw new RuntimeException("Failed to add WS-Security timestamp to outbound message", e);
            }
        }

        private boolean handleInboundMessage(SOAPMessageContext context) {
            try {
                SOAPMessage message = context.getMessage();
                SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
                SOAPHeader header = envelope.getHeader();

                if (header == null) {
                    System.err.println("[WS-Security] No SOAP header found - rejecting message");
                    generateSOAPFault(context, "Missing WS-Security header");
                    return false;
                }

                // Parse SOAP headers and extract Security element
                Iterator<?> securityHeaders = header.getChildElements(new QName(WSS_NS, "Security"));

                if (!securityHeaders.hasNext()) {
                    System.err.println("[WS-Security] No WS-Security header found - rejecting message");
                    generateSOAPFault(context, "Missing WS-Security Security header");
                    return false;
                }

                SOAPElement securityElement = (SOAPElement) securityHeaders.next();

                // Extract timestamp values from the security header
                Iterator<?> timestamps = securityElement.getChildElements(new QName(WSU_NS, "Timestamp"));

                if (!timestamps.hasNext()) {
                    System.err.println("[WS-Security] No Timestamp found in Security header - rejecting message");
                    generateSOAPFault(context, "Missing Timestamp in WS-Security header");
                    return false;
                }

                SOAPElement timestampElement = (SOAPElement) timestamps.next();

                // Extract timestamp ID for replay detection
                String timestampId = null;
                try {
                    timestampId = timestampElement.getAttributeValue(new QName(WSU_NS, "Id"));
                } catch (Exception e) {
                    // ID might not be present
                }

                // Parse Created and Expires timestamp values
                String createdValue = extractElementText(timestampElement, WSU_NS, "Created");
                String expiresValue = extractElementText(timestampElement, WSU_NS, "Expires");

                System.out.println("[WS-Security] Inbound Timestamp - Id: " + timestampId +
                        ", Created: " + createdValue + ", Expires: " + expiresValue);

                if (createdValue == null || createdValue.isEmpty()) {
                    System.err.println("[WS-Security] Created timestamp is missing");
                    generateSOAPFault(context, "Created timestamp is required");
                    return false;
                }

                Date createdDate = parseTimestamp(createdValue);
                Date expiresDate = (expiresValue != null && !expiresValue.isEmpty()) ? parseTimestamp(expiresValue) : null;
                Date now = new Date();

                if (createdDate == null) {
                    System.err.println("[WS-Security] Invalid Created timestamp format: " + createdValue);
                    generateSOAPFault(context, "Invalid Created timestamp format");
                    return false;
                }

                // Check if message is too old (replay protection)
                long ageMs = now.getTime() - createdDate.getTime();
                if (ageMs > TIMESTAMP_FRESHNESS_MS) {
                    System.err.println("[WS-Security] Message timestamp is stale. Age: " + ageMs + "ms, Max: " + TIMESTAMP_FRESHNESS_MS + "ms");
                    generateSOAPFault(context, "Message timestamp is expired (too old). Possible replay attack.");
                    return false;
                }

                // Check if message is from the future (clock skew tolerance: 60 seconds)
                long futureToleranceMs = 60 * 1000;
                if (createdDate.getTime() > now.getTime() + futureToleranceMs) {
                    System.err.println("[WS-Security] Message timestamp is in the future");
                    generateSOAPFault(context, "Message timestamp is in the future. Clock synchronization issue.");
                    return false;
                }

                // Check Expires if present
                if (expiresDate != null) {
                    if (now.after(expiresDate)) {
                        System.err.println("[WS-Security] Message has expired at: " + expiresValue);
                        generateSOAPFault(context, "Message has expired. Expires: " + expiresValue);
                        return false;
                    }
                }

                // Replay detection using timestamp ID and created value
                String messageFingerprint = (timestampId != null ? timestampId : "") + "|" + createdValue;
                if (processedMessageIds.contains(messageFingerprint)) {
                    System.err.println("[WS-Security] Replay attack detected! Message fingerprint: " + messageFingerprint);
                    generateSOAPFault(context, "Replay attack detected. This message has already been processed.");
                    return false;
                }

                // Store message fingerprint for replay detection
                addToProcessedMessages(messageFingerprint);

                System.out.println("[WS-Security] Timestamp validation passed for message: " + messageFingerprint);
                return true;

            } catch (SOAPException e) {
                System.err.println("[WS-Security] Error processing security header: " + e.getMessage());
                generateSOAPFault(context, "Error processing WS-Security header: " + e.getMessage());
                return false;
            }
        }

        private String extractElementText(SOAPElement parent, String namespace, String localName) {
            Iterator<?> elements = parent.getChildElements(new QName(namespace, localName));
            if (elements.hasNext()) {
                SOAPElement element = (SOAPElement) elements.next();
                return element.getTextContent();
            }
            return null;
        }

        private Date parseTimestamp(String timestamp) {
            try {
                synchronized (ISO_FORMAT) {
                    return ISO_FORMAT.parse(timestamp);
                }
            } catch (Exception e1) {
                try {
                    synchronized (ISO_FORMAT_NO_MILLIS) {
                        return ISO_FORMAT_NO_MILLIS.parse(timestamp);
                    }
                } catch (Exception e2) {
                    // Try with timezone offset format
                    try {
                        SimpleDateFormat altFormat = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ssXXX");
                        altFormat.setTimeZone(TimeZone.getTimeZone("UTC"));
                        return altFormat.parse(timestamp);
                    } catch (Exception e3) {
                        return null;
                    }
                }
            }
        }

        private String formatTimestamp(Date date) {
            synchronized (ISO_FORMAT) {
                return ISO_FORMAT.format(date);
            }
        }

        private void addToProcessedMessages(String fingerprint) {
            processedMessageIds.add(fingerprint);
            messageIdOrder.addLast(fingerprint);

            // Evict old entries to prevent unbounded growth
            while (messageIdOrder.size() > MAX_NONCE_CACHE_SIZE) {
                String oldest = messageIdOrder.pollFirst();
                if (oldest != null) {
                    processedMessageIds.remove(oldest);
                }
            }
        }

        private void generateSOAPFault(SOAPMessageContext context, String faultMessage) {
            try {
                SOAPMessage soapMessage = context.getMessage();
                SOAPBody body = soapMessage.getSOAPBody();
                body.removeContents();
                SOAPFault fault = body.addFault();
                fault.setFaultCode(new QName("http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd",
                        "InvalidSecurity"));
                fault.setFaultString("WS-Security Validation Failed: " + faultMessage);
                soapMessage.saveChanges();
            } catch (SOAPException e) {
                System.err.println("[WS-Security] Failed to generate SOAP fault: " + e.getMessage());
            }
        }

        @Override
        public boolean handleFault(SOAPMessageContext context) {
            System.err.println("[WS-Security] SOAP Fault encountered in handler");
            try {
                SOAPMessage message = context.getMessage();
                if (message != null) {
                    message.writeTo(System.err);
                    System.err.println();
                }
            } catch (Exception e) {
                System.err.println("[WS-Security] Error logging fault: " + e.getMessage());
            }
            return true;
        }

        @Override
        public void close(MessageContext context) {
            // Cleanup if necessary
        }
    }

    // --- Handler Resolver ---

    public static class PaymentHandlerResolver implements HandlerResolver {
        @Override
        @SuppressWarnings("rawtypes")
        public List<Handler> getHandlerChain(PortInfo portInfo) {
            List<Handler> handlerChain = new ArrayList<>();
            handlerChain.add(new WsSecurityTimestampHandler());
            return handlerChain;
        }
    }

